import { Box, CircularProgress, Container, Grid, makeStyles, Menu, MenuItem, Typography } from '@material-ui/core'
import React, { useEffect, useState } from 'react'
import ClassroomCards from '../components/ClassroomCards'
import axios from 'axios'
import { useNavigate } from 'react-router-dom'

import Cookies from 'js-cookie'

const width = 70;
const smwidth = 20;
const useStyle = makeStyles(theme => {
    return {
        root: {
            width: `calc(100% - ${width})`,
            marginLeft: width,
            marginRight: width,
            [theme.breakpoints.down('sm')]: {
                width: `calc(100% - ${smwidth})`,
                marginLeft: smwidth,
                marginRight: smwidth,
            }

        },
        loading: {
            marginTop: theme.spacing(20),
        },
        loadingContainer: {
            border: '1px solid black',
            display: 'flex',
            justifyContent: 'center',
            position: 'fixed',
            width: '100%'
        },
        dashContainer: {
            marginLeft: smwidth,
            [theme.breakpoints.down('sm')]: {
                marginLeft: 0,
            }
        },
        noClassText: {
            maxWidth: 230,
            margin: '0 auto'
        }

    }
});


export default function TeacherDashboard() {

    const classes = useStyle();

    const navigate = useNavigate();
    const [isLoading, setIsLoading] = useState(true);
    const Cookie = Cookies.get('instructorID');

    const [noClassroom, setNoClassroom] = useState(true);

    function sessionCheck() {
        if (!Cookie) {
            navigate('/');
        }
    }

    const [subjects, setSubjects] = useState([]);
    const showClassrooms = () => {
        axios.post('https://ursacapi.000webhostapp.com/api/getCreatedClassrooms.php', JSON.stringify(Cookie))
            .then((response) => {
                if (response.data == 0) {
                    setNoClassroom(true);
                } else {
                    setSubjects(response.data);
                    // setIsLoading(false)
                    setNoClassroom(false);

                }
            })
            .catch(err => console.log(err))
    }



    useEffect(() => {
        sessionCheck();
        showClassrooms();
    }, []);



    return (
        <Box className={classes.root}>
            {
                isLoading ?


                    <Box className={classes.loadingContainer}>
                        <CircularProgress className={classes.loading} color='secondary' />
                    </Box>


                    :

                    <Box>
                        {
                            noClassroom ?


                                <Box className={classes.noClassText}>
                                    <MenuItem disabled>
                                        You have no classroom yet.
                                    </MenuItem>
                                </Box>
                                :

                                <Box className={classes.dashContainer}>

                                    <Grid container spacing={4}>
                                        {/* <div>{subjects.subjectName}</div> */}
                                        {subjects.map(subject => (
                                            <Grid item key={subject.id}>
                                                <ClassroomCards subject={subject} />
                                            </Grid>
                                        ))}
                                    </Grid>
                                </Box>

                        }

                    </Box>
            }
        </Box>

    )
}
